11→  } catch {
12→    // db unreachable
13→  }
14→
15→  const body = JSON.stringify({ status: dbStatus === "ok" ? "ok" : "error", db: dbStatus, ts: new Date().toISOString() });
16→  return new Response(body, {
17→    status: httpStatus,
18→    headers: { "Content-Type": "application/json" },
19→  });
