 1→const API_BASE = import.meta.env.VITE_API_BASE ?? "";
 2→
 3→export function buildUrl(path: string) {
 4→  if (!API_BASE) return path;
 5→  return `${API_BASE}${path.startsWith("/") ? path : `/${path}`}`;
 6→}
 7→
 8→export async function apiFetch(path: string, init: RequestInit = {}) {
 9→  return fetch(buildUrl(path), {
10→    credentials: "include",
11→    ...init,
12→    headers: {
13→      ...(init.headers ?? {}),
14→    },
15→  });
16→}
17→
18→export async function apiJson<T>(path: string, init: RequestInit = {}): Promise<T> {
19→  const response = await apiFetch(path, init);
20→  if (!response.ok) {
21→    const text = await response.text();
22→    throw new Error(text || "Request failed");
23→  }
24→  return (await response.json()) as T;
25→}
