15→export async function GET(request: Request): Promise<Response> {
16→  const auth = await requireUser(request);
17→  if (!auth) return errorResponse("Unauthorized", 401);
18→  const authIsAdmin = (auth.token as { isAdmin?: unknown } | undefined)?.isAdmin === true;
19→
20→  try {
21→    const profile = await getUserProfile(auth.id);
22→    if (!profile) return errorResponse("Profile not found", 404);
23→
24→    if (authIsAdmin && (!profile.isAdmin || profile.mapScope !== "global")) {
25→      profile.isAdmin = true;
26→      profile.mapScope = "global";
27→      await upsertUserProfile(auth.id, profile);
28→    }
29→
30→    return jsonResponse(profile, { status: 200 });
31→  } catch (error) {
32→    if (isStorageUnavailableError(error)) {
33→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
34→    }
35→    throw error;
36→  }
37→}
38→
39→interface UpdateUserBody {
40→  occupation?: unknown;
41→  mapScope?: unknown;
42→}
43→
44→export async function PUT(request: Request): Promise<Response> {
45→  const auth = await requireUser(request);
46→  if (!auth) return errorResponse("Unauthorized", 401);
47→
48→  let body: UpdateUserBody;
49→  try {
50→    body = (await request.json()) as UpdateUserBody;
51→  } catch {
52→    return errorResponse("Invalid JSON body", 400);
53→  }
54→
55→  try {
56→    const profile = await getUserProfile(auth.id);
57→    if (!profile) return errorResponse("Profile not found", 404);
58→
59→    if (body?.occupation !== undefined) {
60→      if (typeof body.occupation !== "string") return errorResponse("Invalid occupation", 400);
61→      const normalized = body.occupation.trim();
62→      if (normalized.length > 120) return errorResponse("Occupation exceeds maximum length", 400);
63→      profile.occupation = normalized;
64→    }
65→
66→    if (body?.mapScope !== undefined) {
67→      const nextScope = normalizeMapScope(body.mapScope);
68→      if (!nextScope) return errorResponse("Invalid mapScope", 400);
69→      if (!profile.isAdmin && nextScope !== "bonamoussadi") {
70→        return errorResponse("Only admin users can unlock map scope", 403);
71→      }
72→      profile.mapScope = nextScope;
73→    }
74→
75→    await upsertUserProfile(auth.id, profile);
76→    return jsonResponse(profile, { status: 200 });
77→  } catch (error) {
78→    if (isStorageUnavailableError(error)) {
79→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
80→    }
81→    throw error;
82→  }
83→}
