192→    [
193→      params.id,
194→      legacyEmail,
195→      params.name,
196→      params.image,
197→      params.occupation,
198→      params.xp,
199→      params.passwordHash,
200→      params.isAdmin,
201→      params.mapScope,
202→    ],
