164→function parseImagePayload(imageBase64: string): { imageBuffer: Buffer; mime: string; ext: string } | null {
165→  const match = imageBase64.match(INLINE_IMAGE_REGEX);
166→  if (!match) return null;
167→
168→  const mime = match[1]?.toLowerCase() ?? "";
169→  if (!allowedImageMime.has(mime)) return null;
170→
171→  const base64 = stripBase64Prefix(imageBase64);
172→  const imageBuffer = Buffer.from(base64, "base64");
173→  if (!imageBuffer.length) return null;
174→
175→  return { imageBuffer, mime, ext: mimeToExtension(mime) };
176→}
