280→async function buildFallbackFraudCheck(event: PointEvent): Promise<SubmissionFraudCheck | null> {
281→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
282→  const secondaryUrl = getSecondaryPhotoUrl(event);
283→  if (!primaryUrl && !secondaryUrl) return null;
284→
285→  const primaryExtracted = primaryUrl ? await extractPhotoMetadataFromUrl(primaryUrl) : null;
286→  const secondaryExtracted = secondaryUrl ? await extractPhotoMetadataFromUrl(secondaryUrl) : null;
287→  const primaryPhoto = buildPhotoFraudMetadata({
288→    extracted: primaryExtracted,
289→    submissionLocation: event.location,
290→    ipLocation: null,
291→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
292→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
293→  });
294→  const secondaryPhoto = buildPhotoFraudMetadata({
