29→    config: {
30→      responseModalities: [Modality.AUDIO],
31→      speechConfig: {
32→        voiceConfig: {
33→          prebuiltVoiceConfig: { voiceName: 'Kore' },
34→        },
35→      },
36→    },
37→  });
38→
39→  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
40→  if (!base64Audio) throw new Error("No audio generated");
41→
42→  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
43→  const audioData = decodeBase64(base64Audio);
44→  const audioBuffer = await decodeAudioData(audioData, audioContext, 24000, 1);
45→  
46→  const source = audioContext.createBufferSource();
47→  source.buffer = audioBuffer;
48→  source.connect(audioContext.destination);
49→  source.start();
50→}
51→
52→export async function transcribeAudio(base64Audio: string) {
53→  const response = await ai.models.generateContent({
54→    model: "gemini-3-flash-preview",
55→    contents: {
56→      parts: [
57→        { inlineData: { mimeType: "audio/wav", data: base64Audio } },
58→        { text: "Transcribe the spoken audio precisely." }
59→      ]
60→    }
61→  });
62→  return response.text;
63→}
64→
65→// Helper functions for audio processing
66→function decodeBase64(base64: string) {
67→  const binaryString = atob(base64);
68→  const bytes = new Uint8Array(binaryString.length);
69→  for (let i = 0; i < binaryString.length; i++) {
70→    bytes[i] = binaryString.charCodeAt(i);
71→  }
72→  return bytes;
73→}
74→
75→async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
76→  const dataInt16 = new Int16Array(data.buffer);
77→  const frameCount = dataInt16.length / numChannels;
78→  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
79→  for (let channel = 0; channel < numChannels; channel++) {
80→    const channelData = buffer.getChannelData(channel);
81→    for (let i = 0; i < frameCount; i++) {
82→      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
83→    }
84→  }
85→  return buffer;
86→}
