 35→
 36→function normalizeString(input: unknown): string | null {
 37→  if (typeof input !== "string") return null;
 38→  const value = input.trim();
 39→  return value || null;
 40→}
 41→
 42→function parseDateIso(input: unknown): string | null {
 43→  if (!input) return null;
 44→  if (input instanceof Date) {
 45→    if (Number.isNaN(input.getTime())) return null;
 46→    return input.toISOString();
 47→  }
 48→  if (typeof input === "string" || typeof input === "number") {
 49→    const parsed = new Date(input);
 50→    if (Number.isNaN(parsed.getTime())) return null;
 51→    return parsed.toISOString();
 52→  }
 53→  return null;
 54→}
 55→
 56→function parseLocation(input: unknown): SubmissionLocation | null {
 57→  if (!input || typeof input !== "object") return null;
 58→  const location = input as { latitude?: unknown; longitude?: unknown };
 59→  const latitude = typeof location.latitude === "number" ? location.latitude : Number(location.latitude);
 60→  const longitude = typeof location.longitude === "number" ? location.longitude : Number(location.longitude);
 61→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 62→  return { latitude, longitude };
 63→}
 64→
 65→function parseOptionalNumber(input: unknown): number | null {
 66→  if (typeof input === "number" && Number.isFinite(input)) return input;
 67→  if (typeof input === "string") {
 68→    const parsed = Number(input);
 69→    if (Number.isFinite(parsed)) return parsed;
 70→  }
 71→  return null;
 72→}
 73→
 74→function parseOptionalBoolean(input: unknown): boolean | null {
 75→  if (typeof input === "boolean") return input;
 76→  return null;
 77→}
 78→
 79→function roundKm(input: number): number {
 80→  return Number(input.toFixed(KM_PRECISION));
 81→}
 82→
 83→export function haversineKm(a: SubmissionLocation, b: SubmissionLocation): number {
 84→  const toRad = (deg: number) => (deg * Math.PI) / 180;
 85→  const dLat = toRad(b.latitude - a.latitude);
 86→  const dLon = toRad(b.longitude - a.longitude);
 87→  const lat1 = toRad(a.latitude);
 88→  const lat2 = toRad(b.latitude);
 89→  const sinLat = Math.sin(dLat / 2);
 90→  const sinLon = Math.sin(dLon / 2);
 91→  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLon * sinLon;
 92→  return 2 * EARTH_RADIUS_KM * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h));
 93→}
