 95→export async function extractPhotoMetadata(imageBuffer: Buffer): Promise<ExtractedPhotoMetadata> {
 96→  const parsed = (await exifr.parse(imageBuffer, {
 97→    gps: true,
 98→    exif: true,
 99→    tiff: true,
100→  })) as Record<string, unknown> | null;
101→
102→  if (!parsed) {
103→    return {
104→      gps: null,
105→      capturedAt: null,
106→      deviceMake: null,
107→      deviceModel: null,
108→    };
109→  }
110→
111→  const latitude = typeof parsed.latitude === "number" ? parsed.latitude : Number(parsed.latitude);
112→  const longitude = typeof parsed.longitude === "number" ? parsed.longitude : Number(parsed.longitude);
113→  const gps = Number.isFinite(latitude) && Number.isFinite(longitude) ? { latitude, longitude } : null;
114→
115→  const capturedAt =
116→    parseDateIso(parsed.DateTimeOriginal) ??
117→    parseDateIso(parsed.DateTimeDigitized) ??
118→    parseDateIso(parsed.CreateDate) ??
119→    parseDateIso(parsed.ModifyDate);
120→
121→  return {
122→    gps,
123→    capturedAt,
124→    deviceMake: normalizeString(parsed.Make),
125→    deviceModel: normalizeString(parsed.Model),
126→  };
127→}
