151→export function buildPhotoFraudMetadata(params: BuildPhotoFraudMetadataParams): SubmissionPhotoMetadata | null {
152→  if (!params.extracted) return null;
153→
154→  const { extracted, submissionLocation, ipLocation, submissionMatchThresholdKm, ipMatchThresholdKm } = params;
155→  const gps = extracted.gps;
156→
157→  const submissionDistanceRaw = gps && submissionLocation ? haversineKm(submissionLocation, gps) : null;
158→  const ipDistanceRaw = gps && ipLocation ? haversineKm(ipLocation, gps) : null;
159→
160→  const submissionDistanceKm = submissionDistanceRaw === null ? null : roundKm(submissionDistanceRaw);
161→  const ipDistanceKm = ipDistanceRaw === null ? null : roundKm(ipDistanceRaw);
162→
163→  return {
164→    gps,
165→    capturedAt: extracted.capturedAt,
166→    deviceMake: extracted.deviceMake,
167→    deviceModel: extracted.deviceModel,
168→    submissionDistanceKm,
169→    submissionGpsMatch: submissionDistanceKm === null ? null : submissionDistanceKm <= submissionMatchThresholdKm,
170→    ipDistanceKm,
171→    ipGpsMatch: ipDistanceKm === null ? null : ipDistanceKm <= ipMatchThresholdKm,
172→  };
173→}
