285→  const primaryExtracted = primaryUrl ? await extractPhotoMetadataFromUrl(primaryUrl) : null;
286→  const secondaryExtracted = secondaryUrl ? await extractPhotoMetadataFromUrl(secondaryUrl) : null;
287→  const primaryPhoto = buildPhotoFraudMetadata({
288→    extracted: primaryExtracted,
289→    submissionLocation: event.location,
290→    ipLocation: null,
291→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
292→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
293→  });
294→  const secondaryPhoto = buildPhotoFraudMetadata({
295→    extracted: secondaryExtracted,
296→    submissionLocation: event.location,
297→    ipLocation: null,
298→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
299→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
300→  });
301→  if (!primaryPhoto && !secondaryPhoto) return null;
302→
303→  return buildSubmissionFraudCheck({
304→    submissionLocation: event.location,
305→    effectiveLocation: event.location,
306→    ipLocation: null,
307→    primaryPhoto,
308→    secondaryPhoto,
309→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
310→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
311→  });
312→}
