 72→function hasValue(input: unknown): boolean {
 73→  if (typeof input === "string") return Boolean(input.trim());
 74→  if (typeof input === "boolean") return true;
 75→  if (typeof input === "number") return Number.isFinite(input);
 76→  if (Array.isArray(input)) return input.length > 0;
 77→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 78→  return false;
 79→}
