 76→async function withAbsoluteUrl(request: Request): Promise<Request> {
 77→  try {
 78→    // eslint-disable-next-line no-new
 79→    new URL(request.url);
 80→    return request;
 81→  } catch {
 82→    const base = process.env.AUTH_URL ?? process.env.NEXTAUTH_URL ?? "http://localhost:3000";
 83→    const url = new URL(request.url || "/", base);
 84→    const method = request.method ?? "GET";
 85→    const init: RequestInit = {
 86→      method,
 87→      headers: request.headers,
 88→      redirect: request.redirect,
 89→    };
 90→    if (method !== "GET" && method !== "HEAD") {
 91→      init.body = await request.arrayBuffer();
 92→    }
 93→    return new Request(url, init);
 94→  }
 95→}
