15→export async function GET(request: Request): Promise<Response> {
16→  const auth = await requireUser(request);
17→  if (!auth) return errorResponse("Unauthorized", 401);
18→  const authIsAdmin = (auth.token as { isAdmin?: unknown } | undefined)?.isAdmin === true;
19→
20→  try {
21→    const profile = await getUserProfile(auth.id);
22→    if (!profile) return errorResponse("Profile not found", 404);
23→
24→    if (authIsAdmin && (!profile.isAdmin || profile.mapScope !== "global")) {
25→      profile.isAdmin = true;
26→      profile.mapScope = "global";
27→      await upsertUserProfile(auth.id, profile);
28→    }
29→
30→    return jsonResponse(profile, { status: 200 });
31→  } catch (error) {
32→    if (isStorageUnavailableError(error)) {
33→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
34→    }
35→    throw error;
36→  }
