 45→export async function getUserProfile(userId: string): Promise<UserProfile | null> {
 46→  const primary = getPrimaryStore();
 47→  const primaryProfile = await primary.getUserProfile(userId);
 48→  if (primaryProfile || !shouldUseFallback()) return primaryProfile;
 49→  return await edgeFallbackStore.getUserProfile(userId);
 50→}
