 71→function rowToUserProfile(row: Record<string, unknown>): UserProfile {
 72→  const email = typeof row.email === "string" && row.email.trim() ? row.email.toLowerCase().trim() : null;
 73→  const phone = typeof row.phone === "string" && row.phone.trim() ? row.phone.trim() : null;
 74→  return {
 75→    id: String(row.id ?? "").toLowerCase().trim(),
 76→    email,
 77→    phone,
 78→    name: typeof row.name === "string" ? row.name : "",
 79→    image: typeof row.image === "string" ? row.image : "",
 80→    occupation: typeof row.occupation === "string" ? row.occupation : "",
 81→    XP: parseXp(row.xp),
 82→    passwordHash: typeof row.password_hash === "string" ? row.password_hash : undefined,
 83→    isAdmin: Boolean(row.is_admin),
 84→    mapScope: normalizeMapScope(row.map_scope),
 85→  };
