337→async function deletePointEvent(eventId: string): Promise<boolean> {
338→  const normalizedId = normalizeEventId(eventId);
339→  const result = await query(
340→    `
341→      delete from point_events
342→      where id = $1::uuid
343→    `,
344→    [normalizedId],
345→  );
346→  return result.rowCount > 0;
347→}
