 21→      password: { label: "Password", type: "password" },
 22→    },
 23→    async authorize(credentials) {
 24→      const rawIdentifier =
 25→        typeof credentials?.identifier === "string"
 26→          ? credentials.identifier
 27→          : typeof credentials?.email === "string"
 28→            ? credentials.email
 29→            : "";
 30→      const normalizedIdentifier = normalizeIdentifier(rawIdentifier);
 31→      const password = typeof credentials?.password === "string" ? credentials.password : "";
 32→
 33→      if (!normalizedIdentifier || !password) return null;
 34→      const identifier = normalizedIdentifier.value;
 35→
 36→      const adminEmail = normalizeEmail(process.env.ADMIN_EMAIL);
 37→      const adminPassword = process.env.ADMIN_PASSWORD ?? "";
 38→      if (adminEmail && adminPassword && normalizedIdentifier.type === "email" && identifier === adminEmail) {
 39→        let adminMatch = false;
 40→        if (adminPassword.startsWith("$2")) {
 41→          adminMatch = await bcrypt.compare(password, adminPassword);
 42→        } else {
 43→          // Fallback for plain-text password (legacy). Update ADMIN_PASSWORD to a bcrypt hash.
 44→          console.warn("[auth] ADMIN_PASSWORD is not a bcrypt hash. Please update it to a bcrypt hash.");
 45→          adminMatch = password === adminPassword;
 46→        }
 47→        if (adminMatch) return { id: identifier, name: "Admin", email: identifier };
 48→      }
 49→
 50→      const profile = await getUserProfile(identifier);
 51→      if (!profile?.passwordHash) return null;
 52→
 53→      const valid = bcrypt.compareSync(password, profile.passwordHash);
 54→      if (!valid) return null;
 55→
 56→      const fallbackName = inferDefaultDisplayName(profile.email ?? profile.phone ?? profile.id);
 57→      return { id: profile.id, name: profile.name || fallbackName, email: profile.email ?? undefined };
 58→    },
 59→  }),
 60→];
