103→function mapAuthJsError(errorType: string | null, errorCode: string | null): AuthClientError {
104→  switch (errorType) {
105→    case "CredentialsSignin":
106→      return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
107→    case "Callback":
108→    case "CallbackRouteError":
109→      return new AuthClientError("callback_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
110→    case "Configuration":
111→      return new AuthClientError("configuration_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
112→    case "AccessDenied":
113→      return new AuthClientError("access_denied", "Access denied for this account.");
114→    default:
115→      if (errorCode === "credentials") {
116→        return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
117→      }
118→      return new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
119→  }
120→}
