122→function toAuthClientError(error: unknown, fallback: string): AuthClientError {
123→  if (error instanceof AuthClientError) return error;
124→  if (error instanceof Error) {
125→    return new AuthClientError("unknown_error", sanitizeErrorMessage(error.message, fallback), { cause: error });
126→  }
127→  return new AuthClientError("unknown_error", fallback);
128→}
