190→export async function signInWithCredentials(
191→  identifier: string,
192→  password: string,
193→  options: SignInWithCredentialsOptions = {}
194→): Promise<void> {
195→  const maxAttempts = normalizeAttempts(options.maxAttempts);
196→  const retryDelayMs = normalizeDelayMs(options.retryDelayMs);
197→
198→  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
199→    try {
200→      await signInWithCredentialsOnce(identifier, password);
201→      return;
202→    } catch (error) {
203→      const authError = toAuthClientError(error, DEFAULT_SIGN_IN_ERROR);
204→      const shouldRetry = authError.retryable && attempt < maxAttempts;
205→      if (!shouldRetry) throw authError;
206→      await delay(retryDelayMs);
207→    }
208→  }
209→}
