219→    method: "POST",
220→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
221→    body,
222→  });
223→  if (!response.ok) {
224→    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_OUT_ERROR);
225→    const retryable = response.status >= 500;
226→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
227→  }
228→}
