129→function isHttpUrl(input: string): boolean {
130→  return /^https?:\/\//i.test(input);
131→}
132→
133→export async function extractPhotoMetadataFromUrl(photoUrl: string): Promise<ExtractedPhotoMetadata | null> {
134→  if (!photoUrl || !isHttpUrl(photoUrl)) return null;
135→
136→  const controller = new AbortController();
137→  const timeout = setTimeout(() => controller.abort(), REMOTE_FETCH_TIMEOUT_MS);
138→  try {
139→    const response = await fetch(photoUrl, { signal: controller.signal });
140→    if (!response.ok) return null;
141→    const arrayBuffer = await response.arrayBuffer();
142→    if (!arrayBuffer.byteLength || arrayBuffer.byteLength > MAX_REMOTE_METADATA_BYTES) return null;
143→    return await extractPhotoMetadata(Buffer.from(arrayBuffer));
144→  } catch {
145→    return null;
146→  } finally {
147→    clearTimeout(timeout);
148→  }
149→}
