151→export function buildPhotoFraudMetadata(params: BuildPhotoFraudMetadataParams): SubmissionPhotoMetadata | null {
152→  if (!params.extracted) return null;
153→
154→  const { extracted, submissionLocation, ipLocation, submissionMatchThresholdKm, ipMatchThresholdKm } = params;
155→  const gps = extracted.gps;
156→
157→  const submissionDistanceRaw = gps && submissionLocation ? haversineKm(submissionLocation, gps) : null;
158→  const ipDistanceRaw = gps && ipLocation ? haversineKm(ipLocation, gps) : null;
159→
160→  const submissionDistanceKm = submissionDistanceRaw === null ? null : roundKm(submissionDistanceRaw);
161→  const ipDistanceKm = ipDistanceRaw === null ? null : roundKm(ipDistanceRaw);
162→
163→  return {
164→    gps,
165→    capturedAt: extracted.capturedAt,
166→    deviceMake: extracted.deviceMake,
167→    deviceModel: extracted.deviceModel,
168→    submissionDistanceKm,
169→    submissionGpsMatch: submissionDistanceKm === null ? null : submissionDistanceKm <= submissionMatchThresholdKm,
170→    ipDistanceKm,
171→    ipGpsMatch: ipDistanceKm === null ? null : ipDistanceKm <= ipMatchThresholdKm,
172→  };
173→}
174→
175→export function buildSubmissionFraudCheck(params: BuildSubmissionFraudCheckParams): SubmissionFraudCheck {
176→  return {
177→    submissionLocation: params.submissionLocation,
178→    effectiveLocation: params.effectiveLocation,
179→    ipLocation: params.ipLocation,
180→    primaryPhoto: params.primaryPhoto,
181→    secondaryPhoto: params.secondaryPhoto,
182→    submissionMatchThresholdKm: params.submissionMatchThresholdKm,
183→    ipMatchThresholdKm: params.ipMatchThresholdKm,
184→  };
185→}
186→
187→function parsePhotoFraudMetadata(input: unknown): SubmissionPhotoMetadata | null {
188→  if (!input || typeof input !== "object") return null;
189→  const metadata = input as Record<string, unknown>;
190→
191→  return {
192→    gps: parseLocation(metadata.gps),
193→    capturedAt: parseDateIso(metadata.capturedAt),
194→    deviceMake: normalizeString(metadata.deviceMake),
195→    deviceModel: normalizeString(metadata.deviceModel),
196→    submissionDistanceKm: parseOptionalNumber(metadata.submissionDistanceKm),
197→    submissionGpsMatch: parseOptionalBoolean(metadata.submissionGpsMatch),
198→    ipDistanceKm: parseOptionalNumber(metadata.ipDistanceKm),
199→    ipGpsMatch: parseOptionalBoolean(metadata.ipGpsMatch),
200→  };
201→}
202→
203→export function parseSubmissionFraudCheck(input: unknown): SubmissionFraudCheck | null {
204→  if (!input || typeof input !== "object") return null;
205→  const fraudCheck = input as Record<string, unknown>;
206→  const effectiveLocation = parseLocation(fraudCheck.effectiveLocation);
207→  if (!effectiveLocation) return null;
208→
209→  const submissionMatchThresholdKm =
210→    parseOptionalNumber(fraudCheck.submissionMatchThresholdKm) ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM;
211→  const ipMatchThresholdKm = parseOptionalNumber(fraudCheck.ipMatchThresholdKm) ?? 50;
212→
213→  return {
214→    submissionLocation: parseLocation(fraudCheck.submissionLocation),
215→    effectiveLocation,
216→    ipLocation: parseLocation(fraudCheck.ipLocation),
217→    primaryPhoto: parsePhotoFraudMetadata(fraudCheck.primaryPhoto),
218→    secondaryPhoto: parsePhotoFraudMetadata(fraudCheck.secondaryPhoto),
219→    submissionMatchThresholdKm,
220→    ipMatchThresholdKm,
221→  };
222→}
