  1→import { requireUser } from "../../lib/auth.js";
  2→import { deletePointEvent, getLegacySubmissions, getPointEvents, insertPointEvent, isStorageUnavailableError } from "../../lib/server/storage/index.js";
  3→import { mergePointEventsWithLegacy, normalizeEnrichPayload, projectPointsFromEvents } from "../../lib/server/pointProjection.js";
  4→import { errorResponse, jsonResponse } from "../../lib/server/http.js";
  5→import { canViewEventDetail, toSubmissionAuthContext } from "../../lib/server/submissionAccess.js";
