 30→export async function GET(request: Request): Promise<Response> {
 31→  const auth = await requireUser(request);
 32→  if (!auth) return errorResponse("Unauthorized", 401);
 33→  const viewer = toSubmissionAuthContext(auth);
 34→  if (!viewer) return errorResponse("Unauthorized", 401);
 35→
 36→  const url = new URL(request.url);
 37→  const id = url.pathname.split("/").pop();
 38→  const view = url.searchParams.get("view");
 39→  if (!id) return errorResponse("Missing submission id", 400);
 40→
 41→  let events: PointEvent[];
 42→  try {
 43→    events = await getCombinedEvents();
 44→  } catch (error) {
 45→    if (isStorageUnavailableError(error)) {
 46→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
 47→    }
 48→    throw error;
 49→  }
 50→
 51→  if (view === "event") {
 52→    const event = events.find((item) => item.id === id);
 53→    if (!event) return errorResponse("Submission event not found", 404);
 54→    if (!canViewEventDetail(event, viewer)) return errorResponse("Forbidden", 403);
 55→    return jsonResponse(event, { status: 200 });
 56→  }
 57→
 58→  const points = projectPointsFromEvents(events);
 59→  const point = points.find((item) => item.pointId === id || item.id === id);
 60→  if (point) return jsonResponse(point, { status: 200 });
 61→
 62→  const fallbackEvent = events.find((item) => item.id === id);
 63→  if (fallbackEvent) return jsonResponse(fallbackEvent, { status: 200 });
 64→
 65→  return errorResponse("Submission not found", 404);
 66→}
