 68→export async function PUT(request: Request): Promise<Response> {
 69→  const auth = await requireUser(request);
 70→  if (!auth) return errorResponse("Unauthorized", 401);
 71→
 72→  const url = new URL(request.url);
 73→  const id = url.pathname.split("/").pop();
 74→  if (!id) return errorResponse("Missing submission id", 400);
 75→
 76→  let body: any;
 77→  try {
 78→    body = await request.json();
 79→  } catch {
 80→    return errorResponse("Invalid JSON body", 400);
 81→  }
 82→
 83→  const details = body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : null;
 84→  if (!details) return errorResponse("Missing details payload", 400);
 85→
 86→  try {
 87→    const combinedEvents = await getCombinedEvents();
 88→    const points = projectPointsFromEvents(combinedEvents);
 89→    const targetPoint = points.find((point) => point.pointId === id || point.id === id);
 90→    if (!targetPoint) return errorResponse("Submission not found", 404);
 91→
 92→    const newEvent: PointEvent = {
 93→      id: crypto.randomUUID(),
 94→      pointId: targetPoint.pointId,
 95→      eventType: "ENRICH_EVENT",
 96→      userId: auth.id,
 97→      category: targetPoint.category,
 98→      location: targetPoint.location,
 99→      details: normalizeEnrichPayload(targetPoint.category, details),
100→      photoUrl: typeof body?.photoUrl === "string" ? body.photoUrl : undefined,
101→      createdAt: new Date().toISOString(),
102→      source: "compat_put",
103→    };
104→
105→    await insertPointEvent(newEvent);
106→    return jsonResponse(newEvent, { status: 200 });
107→  } catch (error) {
108→    if (isStorageUnavailableError(error)) {
109→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
110→    }
111→    throw error;
112→  }
113→}
