161→async function removeItem(id: string): Promise<void> {
162→  const db = await openDb();
163→  const tx = db.transaction(STORE_NAME, 'readwrite');
164→  tx.objectStore(STORE_NAME).delete(id);
165→  await transactionDone(tx);
166→  db.close();
167→}
