178→async function uploadSubmissionPhoto(
179→  eventId: string,
180→  imageBuffer: Buffer,
181→  mime: string,
182→  ext: string,
183→): Promise<string> {
184→  const pathname = `submissions/${eventId}-${Date.now()}.${ext}`;
185→  const token = process.env.BLOB_READ_WRITE_TOKEN;
186→  const uploaded = await put(pathname, imageBuffer, {
187→    access: "public",
188→    contentType: mime,
189→    addRandomSuffix: false,
