134→function stripBase64Prefix(imageBase64: string): string {
135→  const commaIndex = imageBase64.indexOf(",");
136→  return commaIndex === -1 ? imageBase64 : imageBase64.slice(commaIndex + 1);
137→}
138→
139→function isInlinePhotoData(value: unknown): value is string {
140→  return typeof value === "string" && value.startsWith(INLINE_PHOTO_PREFIX);
141→}
142→
143→function stripInlinePhotoData(event: PointEvent): PointEvent {
144→  if (!isInlinePhotoData(event.photoUrl)) return event;
145→  const { photoUrl: _photoUrl, ...rest } = event;
146→  const details = { ...(event.details ?? {}), hasPhoto: true };
147→  return { ...rest, details };
148→}
