150→function mimeToExtension(mime: string): string {
151→  switch (mime) {
152→    case "image/png":
153→      return "png";
154→    case "image/webp":
155→      return "webp";
156→    case "image/heic":
157→      return "heic";
158→    case "image/heif":
159→      return "heif";
160→    default:
161→      return "jpg";
162→  }
163→}
164→
165→function parseImagePayload(imageBase64: string): { imageBuffer: Buffer; mime: string; ext: string } | null {
166→  const match = imageBase64.match(INLINE_IMAGE_REGEX);
167→  if (!match) return null;
168→
169→  const mime = match[1]?.toLowerCase() ?? "";
170→  if (!allowedImageMime.has(mime)) return null;
171→
172→  const base64 = stripBase64Prefix(imageBase64);
173→  const imageBuffer = Buffer.from(base64, "base64");
174→  if (!imageBuffer.length) return null;
175→
176→  return { imageBuffer, mime, ext: mimeToExtension(mime) };
177→}
