179→async function uploadSubmissionPhoto(
180→  eventId: string,
181→  imageBuffer: Buffer,
182→  mime: string,
183→  ext: string,
184→): Promise<string> {
185→  const pathname = `submissions/${eventId}-${Date.now()}.${ext}`;
186→  const token = process.env.BLOB_READ_WRITE_TOKEN;
187→  const uploaded = await put(pathname, imageBuffer, {
