196→function normalizeIp(raw: string | null): string | null {
197→  if (!raw) return null;
198→  const first = raw.split(",")[0]?.trim();
199→  if (!first) return null;
200→  const cleaned = first.replace(/^\[|\]$/g, "");
201→  if (cleaned.startsWith("::ffff:")) return cleaned.slice(7);
202→  if (/^\d+\.\d+\.\d+\.\d+:\d+$/.test(cleaned)) return cleaned.split(":")[0] ?? null;
203→  return cleaned;
204→}
205→
206→function isPrivateIp(ip: string): boolean {
207→  if (ip === "127.0.0.1" || ip === "::1") return true;
208→  if (ip.startsWith("10.")) return true;
209→  if (ip.startsWith("192.168.")) return true;
210→  if (ip.startsWith("172.")) {
211→    const second = Number(ip.split(".")[1]);
212→    if (second >= 16 && second <= 31) return true;
213→  }
214→  if (ip.startsWith("fc") || ip.startsWith("fd")) return true;
215→  if (ip.startsWith("fe80:")) return true;
216→  return false;
217→}
