252→function validateCreatePayload(category: SubmissionCategory, details: SubmissionDetails): string | null {
253→  const missing = listCreateMissingFields(category, details);
254→  if (missing.length > 0) return `Missing required fields: ${missing.join(", ")}`;
255→  return null;
