257→async function getUserProfilesBatch(ids: string[]): Promise<Map<string, UserProfile>> {
258→  if (!ids.length) return new Map();
259→  const normalizedIds = ids.map(normalizeUserId);
260→
261→  const fetchRows = async (includePhone: boolean): Promise<UserProfile[]> => {
262→    const cols = includePhone
263→      ? "id, email, phone, name, image, occupation, xp, password_hash, is_admin, map_scope"
264→      : "id, email, name, image, occupation, xp, password_hash, is_admin, map_scope";
265→    const result = await query<Record<string, unknown>>(
266→      `select ${cols} from user_profiles where id = ANY($1::text[])`,
267→      [normalizedIds],
268→    );
269→    return result.rows.map(rowToUserProfile);
270→  };
271→
272→  let rows: UserProfile[];
273→  if (phoneColumnState === "missing") {
274→    rows = await fetchRows(false);
275→  } else {
276→    try {
277→      rows = await fetchRows(true);
278→      if (phoneColumnState === "unknown") phoneColumnState = "present";
279→    } catch (error) {
280→      if (!isMissingPhoneColumnError(error)) throw error;
281→      phoneColumnState = "missing";
282→      rows = await fetchRows(false);
283→    }
284→  }
285→
286→  return new Map(rows.map((profile) => [profile.id, profile]));
287→}
