349→async function bulkUpsertPointEvents(events: PointEvent[]): Promise<void> {
350→  if (!events.length) return;
351→
352→  await query("begin");
353→  try {
354→    for (const event of events) {
355→      await insertPointEvent(event);
356→    }
357→    await query("commit");
358→  } catch (error) {
359→    await query("rollback");
360→    throw error;
361→  }
362→}
