 19→type MatchState = 'match' | 'mismatch' | 'unavailable';
 20→
 21→function exifStatusLabel(status: SubmissionPhotoMetadata['exifStatus'] | null | undefined, language: 'en' | 'fr'): string {
 22→  if (status === 'ok') return language === 'fr' ? 'EXIF present' : 'EXIF present';
 23→  if (status === 'fallback_recovered') return language === 'fr' ? 'Recupere via URL' : 'Recovered via URL';
 24→  if (status === 'missing') return language === 'fr' ? 'EXIF absent' : 'EXIF missing';
 25→  if (status === 'unsupported_format') return language === 'fr' ? 'Format non supporte' : 'Unsupported format';
 26→  if (status === 'parse_error') return language === 'fr' ? 'Erreur de lecture EXIF' : 'EXIF parse error';
 27→  return language === 'fr' ? 'Indisponible' : 'Unavailable';
 28→}
 29→
 30→function exifSourceLabel(source: SubmissionPhotoMetadata['exifSource'] | null | undefined, language: 'en' | 'fr'): string {
 31→  if (source === 'upload_buffer') return language === 'fr' ? 'Upload initial' : 'Initial upload';
 32→  if (source === 'remote_url') return language === 'fr' ? 'Photo distante' : 'Remote photo';
 33→  if (source === 'none') return language === 'fr' ? 'Aucune source' : 'No source';
 34→  return language === 'fr' ? 'Indisponible' : 'Unavailable';
 35→}
 36→
 37→function formatLocation(location: SubmissionLocation | null | undefined, unavailable: string): string {
 38→  if (!location) return unavailable;
 39→  return `${location.latitude.toFixed(5)}°, ${location.longitude.toFixed(5)}°`;
 40→}
 41→
 42→function formatDistance(distanceKm: number | null | undefined, unavailable: string): string {
 43→  if (typeof distanceKm !== 'number' || !Number.isFinite(distanceKm)) return unavailable;
 44→  return `${distanceKm.toFixed(3)} km`;
 45→}
 46→
 47→function formatDate(iso: string | null | undefined, unavailable: string): string {
 48→  if (!iso) return unavailable;
 49→  const parsed = new Date(iso);
 50→  if (Number.isNaN(parsed.getTime())) return unavailable;
 51→  return parsed.toLocaleString();
 52→}
 53→
 54→function categoryLabel(category: AdminSubmissionEvent['event']['category'], language: 'en' | 'fr'): string {
 55→  if (category === 'pharmacy') return language === 'fr' ? 'Pharmacie' : 'Pharmacy';
 56→  if (category === 'fuel_station') return language === 'fr' ? 'Station-service' : 'Fuel Station';
 57→  return language === 'fr' ? 'Kiosque mobile money' : 'Mobile Money Kiosk';
 58→}
 59→
 60→function getSiteName(item: AdminSubmissionEvent, language: 'en' | 'fr'): string {
 61→  const details = item.event.details as SubmissionDetails;
 62→  if (typeof details.siteName === 'string' && details.siteName.trim()) return details.siteName.trim();
 63→  if (typeof details.name === 'string' && details.name.trim()) return details.name.trim();
 64→  return language === 'fr' ? 'Soumission sans nom' : 'Unnamed submission';
 65→}
 66→
 67→function getPrimaryImageUrl(item: AdminSubmissionEvent): string | null {
 68→  if (typeof item.event.photoUrl === 'string' && item.event.photoUrl.trim()) return item.event.photoUrl;
 69→  const details = item.event.details as SubmissionDetails;
 70→  if (typeof details.secondPhotoUrl === 'string' && details.secondPhotoUrl.trim()) return details.secondPhotoUrl;
 71→  return null;
 72→}
 73→
 74→function getSecondaryImageUrl(item: AdminSubmissionEvent): string | null {
 75→  const details = item.event.details as SubmissionDetails;
 76→  if (typeof details.secondPhotoUrl === 'string' && details.secondPhotoUrl.trim()) return details.secondPhotoUrl;
 77→  return null;
 78→}
 79→
 80→function getClientDevice(item: AdminSubmissionEvent): ClientDeviceInfo | null {
 81→  const details = item.event.details as SubmissionDetails;
 82→  if (!details.clientDevice || typeof details.clientDevice !== 'object') return null;
 83→  const raw = details.clientDevice as Record<string, unknown>;
 84→  if (typeof raw.deviceId !== 'string' || !raw.deviceId.trim()) return null;
 85→  return {
 86→    deviceId: raw.deviceId.trim(),
 87→    platform: typeof raw.platform === 'string' ? raw.platform.trim() : undefined,
 88→    userAgent: typeof raw.userAgent === 'string' ? raw.userAgent.trim() : undefined,
 89→    deviceMemoryGb: typeof raw.deviceMemoryGb === 'number' && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null,
 90→    hardwareConcurrency:
 91→      typeof raw.hardwareConcurrency === 'number' && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null,
 92→    isLowEnd: raw.isLowEnd === true
 93→  };
 94→}
 95→
 96→function isReadOnlySubmission(item: AdminSubmissionEvent): boolean {
 97→  const source = typeof item.event.source === 'string' ? item.event.source.trim().toLowerCase() : '';
 98→  if (source === 'legacy_submission' || source === 'osm_overpass') return true;
 99→  if (item.event.id.startsWith('legacy-event-')) return true;
100→  return false;
101→}
