103→function getMatchState(fraudCheck: SubmissionFraudCheck | null): MatchState {
104→  const match = fraudCheck?.primaryPhoto?.submissionGpsMatch;
105→  if (match === true) return 'match';
106→  if (match === false) return 'mismatch';
107→  return 'unavailable';
108→}
