205→        setDeleteError('');
206→        setActionMessage('');
207→        const data = await apiJson<AdminSubmissionEvent[]>('/api/submissions?view=admin_events&scope=global');
208→        if (cancelled) return;
209→        const safeItems = Array.isArray(data) ? data : [];
